package com.hospital.management.controller;
import com.hospital.management.model.AuthenticatedUser;import com.hospital.management.service.*;import com.hospital.management.service.impl.AuthenticationServiceImpl;import com.hospital.management.util.CsrfTokenUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/login") public class LoginServlet extends HttpServlet {private final AuthenticationService service;public LoginServlet(){this(new AuthenticationServiceImpl());}public LoginServlet(AuthenticationService s){service=s;}
 protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{HttpSession s=q.getSession(false);if(s!=null&&s.getAttribute("authenticatedUser")!=null){r.sendRedirect(q.getContextPath()+"/dashboard");return;}CsrfTokenUtil.getOrCreateToken(q.getSession(true));q.getRequestDispatcher("/WEB-INF/views/auth/login.jsp").forward(q,r);}
 protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setCharacterEncoding("UTF-8");String username=q.getParameter("username");String password=q.getParameter("password");AuthenticationResult result=service.authenticate(username,password);if(result.isSuccess()){HttpSession old=q.getSession(false);if(old!=null)old.invalidate();HttpSession fresh=q.getSession(true);fresh.setMaxInactiveInterval(30*60);fresh.setAttribute("authenticatedUser",result.getUser());CsrfTokenUtil.getOrCreateToken(fresh);r.sendRedirect(q.getContextPath()+"/dashboard");return;}q.setAttribute("username",username==null?"":username.trim());q.setAttribute("errorMessage",result.getMessage());CsrfTokenUtil.getOrCreateToken(q.getSession(true));q.getRequestDispatcher("/WEB-INF/views/auth/login.jsp").forward(q,r);}}
